"use strict";(self.webpackChunk=self.webpackChunk||[]).push([[89365],{74921(e,t,n){n.r(t),n.d(t,{assets:()=>l,contentTitle:()=>r,default:()=>c,frontMatter:()=>o,metadata:()=>a,toc:()=>d});var a=n(88767),s=n(74848),i=n(28453);const o={title:"How to understand your machine data?",author:"Philipp Zehnder",authorURL:"http://twitter.com/philipp10der",authorImageURL:"/img/zehnder.png"},r=void 0,l={authorsImageUrls:[void 0]},d=[];function h(e){const t={a:"a",li:"li",p:"p",strong:"strong",ul:"ul",...(0,i.R)(),...e.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:(0,s.jsx)("div",{style:{float:"left",paddingRight:"40px"},children:"8 minutes to read"})})}),"\n",(0,s.jsx)("br",{}),"\n",(0,s.jsx)(t.p,{children:"Data is the new oil. Probably everybody of you has heard or read this sentence before.\nIt is often stated how important data and data understanding is for companies today.\nBut what does this actually mean?  How does the data look like that is produced by your machines and systems?\nAnd how can we solve the big challenge to turn this raw data into insights that can be understood by humans?"}),"\n",(0,s.jsx)(t.p,{children:"When it comes to data analytics people often talk about the big players like Google, Facebook, or Netflix which collect a lot of data about their users and their usage behavior.\nThe core of their business model is to use data and turn it into profit. Nowadays all companies have the requirement to analyze their data.\nBut since this was not originally part of their business model it is very challenging for them to catch up.\nTo gain insights from data, it is often referred to advanced analytics and machine learning. Before such techniques can be used some work must be done.\nA first, basic part of that is to understand your data. We do that in four steps, as can be seen in figure below.\nFirst data sources must be accessed, then they can be integrated and for example be stored in a data lake.\nAfter that, we employ rule-based analytics to find patterns and situations.\nIn the end, machine learning and advanced analytics algorithms can be used to get more out of the data.\nThe idea behind those steps is to generate value as early as possible by collecting the low-hanging fruits first.\nWe develop methodologies and tools for the individual steps to also allow domain experts to perform them to bridge the gap between the big tech companies and more traditional industries."}),"\n",(0,s.jsx)("img",{className:"blog-image",style:{maxWidth:"50%"},src:"/img/blog/2018-06-18/01_motivation.png",alt:"Motivation Graphic"}),"\n",(0,s.jsx)(t.p,{children:"The questions we try to answer in these blog posts are:"}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsx)(t.li,{children:(0,s.jsx)(t.strong,{children:"How does data produced by machines look like?"})}),"\n",(0,s.jsx)(t.li,{children:(0,s.jsx)(t.strong,{children:"How can machines and other data sources be accessed?"})}),"\n",(0,s.jsx)(t.li,{children:(0,s.jsx)(t.strong,{children:"How is it possible to process the continuously produced flow of data?"})}),"\n"]}),"\n",(0,s.jsx)(t.p,{children:"We illustrate our ideas with an example which we also use during the whole blog series.\nThe example is a water circle of a cooling system. You can see such a system in the next image.\nIt contains multiple water tanks and pipes that connect those tanks.\nWithin the tanks and the pipes are multiple sensors, which measure for example the water level in the tank, the flow rate in the water pipe, or the temperature of the water.\nAll those sensors are very simple, they make iterative observations and send the sensed measurements to a computer system."}),"\n",(0,s.jsx)("img",{class:"blog-image",style:{maxWidth:"70%"},src:"/img/blog/2018-06-18/02_anlage.png",alt:"Water Circle Image"}),"\n",(0,s.jsx)(t.p,{children:"Before we go into detail, we want to explain the term streaming data, because we focus on machine and sensor data which is continually produced in a streaming fashion.\nThe opposite of streaming data are fixed sized data sets, called batch data.\nSince always new data is produced by sensors, it is not possible to wait till all data is completely produced and then process it.\nDifferent to that is batch data.\nThe advantage of batch data is, when the processing starts no new data is added anymore.\nStreaming data can also be processed with batch processing systems.\nTherefore, a data stream must be separated into fixed chunks which are then processed in a batch fashion.\nThis is possible but the more natural fit is to use streaming systems since they were designed to process streaming data."}),"\n",(0,s.jsxs)(t.p,{children:["In an environment where we process machine data we have different components.\nThe individual components exchange information in the form of ",(0,s.jsx)(t.strong,{children:"events"}),".\nAll assets continually producing data are called ",(0,s.jsx)(t.strong,{children:"data sources"})," (i.e. a sensor, machine or a software system).\nTo access these data sources, ",(0,s.jsx)(t.strong,{children:"adapters"})," are needed.\nAdapters are software components (which can run anywhere, for example directly on the machine or separately on a edge device near the machine) that are able to connect to the data source, extract the sensor information and emit events to the ",(0,s.jsx)(t.strong,{children:"middleware"}),".\nThe middleware is a central component which is an intermediate between the individual components.\nEven if the middleware is a central component, it is not a bottleneck and also not a single point of failure since it is often realized in form of a distributed system.\n",(0,s.jsx)(t.strong,{children:"Processing systems"})," can access data from the middleware, transform it and apply algorithms.\nThis is the component where the data is analyzed and higher-level information is generated.\nIn the end, results can be stored in ",(0,s.jsx)(t.strong,{children:"data bases"}),".\nFrom there, other applications like for example dashboards can access the calculated results.\nThis is the high-level architecture of processing data streams."]}),"\n",(0,s.jsx)("img",{class:"blog-image",src:"/img/blog/2018-06-18/03_architecture.png",alt:"Overall architecture"}),"\n",(0,s.jsxs)(t.p,{children:["Once the events are integrated into a middleware, it must be processed to detect situations and generate higher-level events.\nThis can be done in an ",(0,s.jsx)(t.strong,{children:"Event Processing Network (EPN)"}),".\nAn EPN consists of one or multiple ",(0,s.jsx)(t.strong,{children:"data sources, event processors"})," transforming and detecting patterns in the data and finally ",(0,s.jsx)(t.strong,{children:"data sinks"}),", which can be data bases, alarms or other systems.\nBelow such a pipeline is shown where we have two sensors as data sources: A flow rate sensor measuring the flow rate in a water pipe and a water level sensor in a water tank.\nIt further contains three processing elements, each with a different functionality.\nThe first one detects increases in the water tank, the second one filters out values under a defined threshold.\nThe last of the processing elements detects when both situations occur within a defined time window.\nIn the end, we employ a data sink, which triggers a notification for a service technician once the modeled situation occurs.\nWe call such instances of EPNs processing ",(0,s.jsx)(t.strong,{children:"pipelines"}),"."]}),"\n",(0,s.jsx)("img",{class:"blog-image",src:"/img/blog/2018-06-18/04_pipeline.png",alt:"Example Pipeline"}),"\n",(0,s.jsx)(t.p,{children:"The pipeline in the image before contains three different processing elements.\nThose elements contain the actual algorithms.\nSuch algorithms can be as easy as simple filters on a sensor value or can also be more complex, such as patterns that occur over a period of time.\nBut they can also contain machine learning and advanced analytics algorithms (e.g. neural networks) that perform predictions on data streams.\nEvent processors are just an abstraction that take a data stream as an input and expose a \u201cnew\u201d data stream.\nFurthermore, they contain configuration parameters which can be defined by a user.\nWith this concept, we can create reusable components that can be used in many different pipelines."}),"\n",(0,s.jsx)(t.p,{children:"The goal of StreamPipes is to enable domain experts to do their data analysis themselves by providing tooling, where such processing pipelines can be modeled in a graphical user interface and then executed automatically without the need of an IT expert.\nProcessing engines which are used as the basis of the processing elements in our solution often require a higher technological understanding.\nIf this understanding is available, they can also be used on their own.\nWe use such systems, like Apache Flink, Apache Spark or the brand-new KSQL by Confluent, for the processing but provide an abstraction over them to enable domain experts to model pipelines themselves.\nThis has also the advantages that individual runtime solutions can be exchanged over time.\nFurthermore, we provide a semantic layer for all elements, including data sources, processing elements, and data sinks.\nWith that layer, our system is capable of understanding the meaning and further support the user to ensure that just semantically correct pipelines are created."}),"\n",(0,s.jsx)(t.p,{children:"In this first blog post of our series, we gave a first introduction how data produced by machines and systems can be analyzed and value can be generated out of it.\nIn the following blog posts we explain the individual parts in more detail to provide you with enough knowledge to start analyzing your own data."}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsx)(t.li,{children:(0,s.jsx)(t.strong,{children:(0,s.jsx)(t.a,{href:"/blog/2018/06/18/how-to-understand-your-machine-data",children:"Part 1: Overview"})})}),"\n",(0,s.jsx)(t.li,{children:"Part 2: Data Sources"}),"\n",(0,s.jsx)(t.li,{children:"Part 3: Data Processing Elements"}),"\n",(0,s.jsx)(t.li,{children:"Part 4: Data Sinks"}),"\n",(0,s.jsx)(t.li,{children:"Part 5: Putting it all together (Example Pipeline)"}),"\n",(0,s.jsx)(t.li,{children:"Part 6: Practical Tips"}),"\n"]})]})}function c(e={}){const{wrapper:t}={...(0,i.R)(),...e.components};return t?(0,s.jsx)(t,{...e,children:(0,s.jsx)(h,{...e})}):h(e)}},28453(e,t,n){n.d(t,{R:()=>o,x:()=>r});var a=n(96540);const s={},i=a.createContext(s);function o(e){const t=a.useContext(i);return a.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:o(e.components),a.createElement(i.Provider,{value:t},e.children)}},88767(e){e.exports=JSON.parse('{"permalink":"/blog/2018/06/18/how-to-understand-your-machine-data","source":"@site/blog/2018-06-18-how-to-understand-your-machine-data.md","title":"How to understand your machine data?","description":"8 minutes to read","date":"2018-06-18T00:00:00.000Z","tags":[],"readingTime":6.94,"hasTruncateMarker":true,"authors":[{"name":"Philipp Zehnder","url":"http://twitter.com/philipp10der","imageURL":"/img/zehnder.png","key":null,"page":null}],"frontMatter":{"title":"How to understand your machine data?","author":"Philipp Zehnder","authorURL":"http://twitter.com/philipp10der","authorImageURL":"/img/zehnder.png"},"unlisted":false,"prevItem":{"title":"Preview: StreamPipes release 0.60.0","permalink":"/blog/2018/09/17/preview-060"},"nextItem":{"title":"Welcome to StreamPipes!","permalink":"/blog/2018/06/14/welcome"}}')}}]);